import { unstable_cache } from 'next/cache';
import { getAllProducts } from './db';

export type Product = {
  id: number;
  sku: string;
  name: string;
  category: string;
  price: number;
  inventory: number;
  status: 'active' | 'discontinued';
  lastUpdated: string;
};

/**
 * Cached catalog fetch.
 *
 * Uses the cache tag "products" so that `revalidateTag("products")`
 * invalidates this entry across all consuming views.
 *
 * Stale-while-revalidate semantics — reads never block on a full
 * recomputation unless the cache is cold.
 */
export const getCachedProducts = unstable_cache(
  async (): Promise<Product[]> => {
    const products = await getAllProducts();
    return products as Product[];
  },
  ['products-catalog-list'],
  {
    tags: ['products'],
    /** Never auto-revalidate — only manual sync or deployment resets the cache. */
    revalidate: false,
  }
);

import { revalidateTag } from 'next/cache';
import { getCachedProducts, type Product } from '@/lib/products';

/* ------------------------------------------------------------------ */
/*  Server Action — inline in the page file                           */
/* ------------------------------------------------------------------ */

async function syncCatalog(formData: FormData) {
  'use server';

  // Mark the cached product catalog as stale.
  // Subsequent reads of getCachedProducts() (tagged "products") will
  // re-fetch from the upstream ERP/PIM in the background.
  revalidateTag('products');
}

/* ------------------------------------------------------------------ */
/*  Helpers                                                           */
/* ------------------------------------------------------------------ */

function formatPrice(amount: number): string {
  return new Intl.NumberFormat('en-US', {
    style: 'currency',
    currency: 'USD',
  }).format(amount);
}

function formatDate(iso: string): string {
  return new Intl.DateTimeFormat('en-US', {
    dateStyle: 'medium',
    timeStyle: 'short',
  }).format(new Date(iso));
}

/* ------------------------------------------------------------------ */
/*  Page Component                                                    */
/* ------------------------------------------------------------------ */

export default async function AdminCatalogPage({
  searchParams,
}: {
  searchParams: Promise<{ synced?: string }>;
}) {
  // Reading from a cached data source tagged "products".
  // When the sync action runs, revalidateTag("products") invalidates
  // this cache entry — the next page render fetches fresh data.
  const products: Product[] = await getCachedProducts();

  const { synced } = await searchParams;

  const stats = {
    total: products.length,
    active: products.filter((p) => p.status === 'active').length,
    lowStock: products.filter((p) => p.inventory < 20).length,
    totalValue: products.reduce((sum, p) => sum + p.price * p.inventory, 0),
  };

  return (
    <div className="catalog-page">
      {/* ── Header ─────────────────────────────────────────────── */}

      <header className="catalog-header">
        <div>
          <h1 className="catalog-title">Product Catalog</h1>
          <p className="catalog-subtitle">
            {stats.active} of {stats.total} products active —
            {stats.lowStock > 0
              ? ` ${stats.lowStock} SKUs low on stock`
              : ' all SKUs well-stocked'}
          </p>
        </div>

        <form action={syncCatalog} method="POST">
          <button type="submit" className="btn btn-primary">
            Sync latest catalog
          </button>
        </form>
      </header>

      {/* ── Sync feedback banner ───────────────────────────────── */}

      {synced !== undefined && (
        <div className="sync-banner" role="status">
          <span className="sync-banner-icon">&#8635;</span>
          <span>
            Catalog sync triggered — product data is refreshing in the
            background and will be up to date across all views shortly.
          </span>
        </div>
      )}

      {/* ── Stats row ──────────────────────────────────────────── */}

      <div className="stats-row">
        <StatCard label="Total SKUs" value={stats.total} />
        <StatCard label="Active" value={stats.active} />
        <StatCard label="Low stock" value={stats.lowStock} type="warn" />
        <StatCard
          label="Inventory value"
          value={formatPrice(stats.totalValue)}
        />
      </div>

      {/* ── Product table ──────────────────────────────────────── */}

      <div className="table-wrapper">
        <table className="product-table">
          <thead>
            <tr>
              <th>SKU</th>
              <th>Name</th>
              <th>Category</th>
              <th className="num">Price</th>
              <th className="num">Inventory</th>
              <th>Status</th>
              <th>Last updated</th>
            </tr>
          </thead>
          <tbody>
            {products.map((product) => (
              <tr key={product.id}>
                <td className="sku">{product.sku}</td>
                <td className="name">{product.name}</td>
                <td>{product.category}</td>
                <td className="num">{formatPrice(product.price)}</td>
                <td className="num">
                  <span
                    className={
                      product.inventory < 20 ? 'stock-low' : 'stock-ok'
                    }
                  >
                    {product.inventory}
                  </span>
                </td>
                <td>
                  <span
                    className={`badge badge--${product.status === 'active' ? 'active' : 'inactive'}`}
                  >
                    {product.status}
                  </span>
                </td>
                <td className="date">{formatDate(product.lastUpdated)}</td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>

      {/* ── Inline styles (scoped to this page) ────────────────── */}

      <style>{`
        /* -------- Layout -------- */

        .catalog-page {
          max-width: 1120px;
          margin: 0 auto;
          padding: 2rem 1.5rem 4rem;
          font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto,
            Helvetica, Arial, sans-serif;
          color: #1a1a2e;
        }

        .catalog-header {
          display: flex;
          justify-content: space-between;
          align-items: flex-start;
          flex-wrap: wrap;
          gap: 1rem;
          margin-bottom: 1.25rem;
        }

        .catalog-title {
          font-size: 1.625rem;
          font-weight: 700;
          margin: 0 0 0.25rem;
        }

        .catalog-subtitle {
          margin: 0;
          color: #555;
          font-size: 0.9rem;
        }

        /* -------- Sync banner -------- */

        .sync-banner {
          display: flex;
          align-items: center;
          gap: 0.625rem;
          padding: 0.75rem 1rem;
          margin-bottom: 1.25rem;
          background: #eef6ff;
          border: 1px solid #b8d4fe;
          border-radius: 8px;
          font-size: 0.9rem;
          color: #1e40af;
        }

        .sync-banner-icon {
          font-size: 1.25rem;
          flex-shrink: 0;
        }

        /* -------- Stats row -------- */

        .stats-row {
          display: grid;
          grid-template-columns: repeat(auto-fit, minmax(150px, 1fr));
          gap: 1rem;
          margin-bottom: 1.75rem;
        }

        .stat-card {
          background: #f8fafc;
          border: 1px solid #e2e8f0;
          border-radius: 10px;
          padding: 0.875rem 1rem;
        }

        .stat-card__label {
          font-size: 0.75rem;
          text-transform: uppercase;
          letter-spacing: 0.05em;
          color: #64748b;
          margin: 0 0 0.25rem;
        }

        .stat-card__value {
          font-size: 1.5rem;
          font-weight: 700;
          margin: 0;
          color: #0f172a;
        }

        .stat-card--warn .stat-card__value {
          color: #b45309;
        }

        /* -------- Table -------- */

        .table-wrapper {
          overflow-x: auto;
          border: 1px solid #e2e8f0;
          border-radius: 10px;
          background: #fff;
        }

        .product-table {
          width: 100%;
          border-collapse: collapse;
          font-size: 0.875rem;
        }

        .product-table th {
          text-align: left;
          padding: 0.75rem 1rem;
          font-weight: 600;
          font-size: 0.75rem;
          text-transform: uppercase;
          letter-spacing: 0.05em;
          color: #64748b;
          background: #f8fafc;
          border-bottom: 1px solid #e2e8f0;
        }

        .product-table td {
          padding: 0.75rem 1rem;
          border-bottom: 1px solid #f1f5f9;
          vertical-align: middle;
        }

        .product-table tr:last-child td {
          border-bottom: none;
        }

        .product-table th.num,
        .product-table td.num {
          text-align: right;
          font-variant-numeric: tabular-nums;
        }

        .product-table td.sku {
          font-family: "SF Mono", "Fira Code", "Fira Mono", monospace;
          font-size: 0.8rem;
          color: #475569;
        }

        .product-table td.name {
          font-weight: 500;
        }

        .product-table td.date {
          color: #64748b;
          font-size: 0.8rem;
          white-space: nowrap;
        }

        /* -------- Status badge -------- */

        .badge {
          display: inline-block;
          padding: 0.125rem 0.5rem;
          border-radius: 999px;
          font-size: 0.75rem;
          font-weight: 600;
          text-transform: capitalize;
        }

        .badge--active {
          background: #dcfce7;
          color: #166534;
        }

        .badge--inactive {
          background: #fef2f2;
          color: #991b1b;
        }

        /* -------- Stock indicators -------- */

        .stock-low {
          color: #b45309;
          font-weight: 600;
        }

        .stock-ok {
          color: #166534;
        }

        /* -------- Button -------- */

        .btn {
          display: inline-flex;
          align-items: center;
          gap: 0.375rem;
          padding: 0.5rem 1.125rem;
          font-size: 0.875rem;
          font-weight: 600;
          border: none;
          border-radius: 8px;
          cursor: pointer;
          transition: background 0.15s, box-shadow 0.15s;
          white-space: nowrap;
        }

        .btn-primary {
          background: #2563eb;
          color: #fff;
        }

        .btn-primary:hover {
          background: #1d4ed8;
        }

        .btn-primary:active {
          background: #1e40af;
        }
      `}</style>
    </div>
  );
}

/* ------------------------------------------------------------------ */
/*  Stat card sub-component                                           */
/* ------------------------------------------------------------------ */

function StatCard({
  label,
  value,
  type,
}: {
  label: string;
  value: string | number;
  type?: 'warn';
}) {
  return (
    <div className={`stat-card${type === 'warn' ? ' stat-card--warn' : ''}`}>
      <p className="stat-card__label">{label}</p>
      <p className="stat-card__value">{value}</p>
    </div>
  );
}

import type { Metadata } from 'next';

export const metadata: Metadata = {
  title: {
    default: 'Admin - Product Catalog',
    template: '%s | Admin',
  },
  description: 'Admin product catalog management for the e-commerce platform.',
};

export default function RootLayout({
  children
}: Readonly<{
  children: React.ReactNode;
}>) {
  return (
    <html lang="en">
      <body>{children}</body>
    </html>
  );
}

import Link from 'next/link';

export default function HomePage() {
  return (
    <main style={{ maxWidth: 640, margin: '4rem auto', padding: '0 1.5rem', fontFamily: 'system-ui, sans-serif' }}>
      <h1 style={{ fontSize: '1.5rem', marginBottom: '0.5rem' }}>E-Commerce Admin</h1>
      <p style={{ color: '#555', marginBottom: '2rem' }}>
        Internal tools for managing products, orders, and catalog data.
      </p>
      <ul style={{ listStyle: 'none', padding: 0, display: 'flex', flexDirection: 'column', gap: '0.75rem' }}>
        <li>
          <Link
            href="/admin/catalog"
            style={{
              display: 'block',
              padding: '0.75rem 1rem',
              background: '#f8fafc',
              border: '1px solid #e2e8f0',
              borderRadius: 8,
              textDecoration: 'none',
              color: '#1a1a2e',
              fontWeight: 600,
            }}
          >
            Product Catalog &rarr;
          </Link>
        </li>
      </ul>
    </main>
  );
}

