import { revalidateTag } from 'next/cache';
import { redirect } from 'next/navigation';
import { getCachedProducts, type Product } from '@/lib/products';

/* ------------------------------------------------------------------ */
/*  Server Action — inline in the page file                           */
/* ------------------------------------------------------------------ */

async function syncCatalog(formData: FormData) {
  'use server';

  // Mark cached catalog data tagged "products" as stale.
  // Subsequent reads of getCachedProducts() will re-fetch from the
  // upstream ERP/PIM in the background. The 'seconds' cache-life
  // profile ensures the revalidated entry stays fresh for a short
  // window, matching the admin expectation of a responsive UI that
  // converges quickly after a manual sync.
  revalidateTag('products', 'seconds');

  // Redirect back with a query param so the page shows a sync banner.
  // The admin sees the page immediately — the freshest cached data
  // renders while the background revalidation populates the new value.
  redirect('/admin/catalog?synced=1');
}
